// Parse request for different Claude use cases
const input = $input.first().json.body || $input.first().json;

const testCase = input.test_case || "simple";
const data = input.data || "";

let promptData = {
  prompt: "",
  json: false,
  max_turns: 1,
  test_case: testCase,
  description: ""
};

switch(testCase) {
  case "simple":
    // Simple question
    promptData.prompt = "What is the capital of France?";
    promptData.description = "Simple question test";
    break;

  case "math":
    // Math problem
    promptData.prompt = "Calculate: (15 * 23) + (47 / 3) - 12";
    promptData.description = "Math calculation test";
    break;

  case "json":
    // JSON output
    promptData.prompt = "List 3 programming languages with their creation years";
    promptData.json = true;
    promptData.description = "JSON output test";
    break;

  case "code_review":
    // Code review
    const code = data || `function fibonacci(n) {\n  if (n <= 1) return n;\n  return fibonacci(n - 1) + fibonacci(n - 2);\n}`;
    promptData.prompt = `Review this code for performance and suggest improvements:\n${code}`;
    promptData.description = "Code review test";
    break;

  case "tech_lead":
    // Tech LEAD decision making
    const context = {
      role: "Tech LEAD",
      task: "select_issue",
      issues: [
        {number: 1, title: "Add user authentication", priority: "high"},
        {number: 2, title: "Fix typo in README", priority: "low"},
        {number: 3, title: "Implement API endpoints", priority: "medium"}
      ]
    };
    promptData.prompt = `You are Tech LEAD. Context: ${JSON.stringify(context)}. Analyze these issues and select which one to work on first. Output your decision as JSON with fields: selected_issue_number, reasoning, estimated_hours`;
    promptData.json = true;
    promptData.description = "Tech LEAD decision test";
    break;

  case "multi_turn":
    // Multi-turn conversation
    promptData.prompt = "First, explain what recursion is. Then give a Python example.";
    promptData.max_turns = 2;
    promptData.description = "Multi-turn test";
    break;

  default:
    // Custom prompt from input
    promptData.prompt = input.prompt || "Hello, Claude";
    promptData.description = "Custom prompt test";
}

promptData.timestamp = new Date().toISOString();

return promptData;

// Process and format the Claude response
const request = $node["Prepare Test Cases"].json;
const response = $input.first().json;

let result = {
  success: response.success || false,
  test_case: request.test_case,
  description: request.description,
  prompt: request.prompt,
  timestamp: request.timestamp,
  response: response.stdout || "",
  parsed_json: null,
  error: response.stderr || "",
  command: response.command || "",
  execution_time: null
};

// Calculate execution time (rough estimate)
const start = new Date(request.timestamp);
const end = new Date();
result.execution_time = `${(end - start) / 1000}s`;

// Try to parse as JSON if it looks like JSON
if (result.response && (result.response.startsWith('{') || result.response.startsWith('['))) {
  try {
    result.parsed_json = JSON.parse(result.response);
  } catch (e) {
    // Not JSON or invalid JSON, keep as string
  }
}

// Add metadata for Tech LEAD integration
if (request.test_case === "tech_lead" && result.parsed_json) {
  result.tech_lead_decision = {
    ready_for_execution: true,
    selected_issue: result.parsed_json.selected_issue_number,
    reasoning: result.parsed_json.reasoning,
    estimated_hours: result.parsed_json.estimated_hours
  };
}

return result;
